import{_ as t,o as n,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"F15: 關係人交易與利益輸送風險 - 財務分析專家 (finance-financial-analyst) 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3135_凌航/20260430/F15_關係人交易與利益輸送風險_財務分析專家.md","filePath":"審計報告庫/財務審計/3135_凌航/20260430/F15_關係人交易與利益輸送風險_財務分析專家.md"}'),o={name:"審計報告庫/財務審計/3135_凌航/20260430/F15_關係人交易與利益輸送風險_財務分析專家.md"};function i(s,a,l,c,h,_){return n(),r("div",null,[...a[0]||(a[0]=[e('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f15-關係人交易與利益輸送風險-財務分析專家-finance-financial-analyst-審計報告" tabindex="-1">F15: 關係人交易與利益輸送風險 - 財務分析專家 (finance-financial-analyst) 審計報告 <a class="header-anchor" href="#f15-關係人交易與利益輸送風險-財務分析專家-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F15: 關係人交易與利益輸送風險 - 財務分析專家 (finance-financial-analyst) 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>是否存在異常大額的關係人交易（連屬公司、子公司）？其定價是否符合市場行情？是否存在利益輸送或虛增利潤之嫌？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至 2024 年最新公開數據，凌航（3135）關係人交易佔比極低（銷貨約 2.3%、進貨約 0.4%），無子公司與資金貸與，2024 年度未公告任何關係人交易事項。治理風險等級：<strong>低</strong>。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>關係人佔比</strong>：2023 銷貨 $55,528K/營收 $243.4B = <strong>2.28%</strong>；進貨 $9,472K/成本 $226.2B = <strong>0.42%</strong></li><li><strong>應收帳款</strong>：泰特 $12,475K，帳期 <strong>83 天</strong></li><li><strong>子公司</strong>：零子公司、零資金貸與；背書保證 $1.01M</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、關係人交易規模實測" tabindex="-1">一、關係人交易規模實測 <a class="header-anchor" href="#一、關係人交易規模實測" aria-label="Permalink to &quot;一、關係人交易規模實測&quot;">​</a></h3><p>2023 年度（112 年度）凌航對關係人「泰特科技」之銷貨收入 $55,173K 加計加工收入 $355K，合計 $55,528K，佔全年營收 $2,433,940K 之 <strong>2.28%</strong>。進貨自泰特 $9,472K，佔營業成本 $2,262,237K 之 <strong>0.42%</strong>。兩項比例均遠低於 20% 高風險警戒線，無重大利益輸送之規模基礎。</p><h3 id="二、應收-應付關係人款項帳期分析" tabindex="-1">二、應收／應付關係人款項帳期分析 <a class="header-anchor" href="#二、應收-應付關係人款項帳期分析" aria-label="Permalink to &quot;二、應收／應付關係人款項帳期分析&quot;">​</a></h3><p>截至 2023 年底，凌航對泰特之應收帳款餘額 $12,475K，對應 2023 年度銷貨 $55,528K，推算帳期約 <strong>83 天</strong>；應付泰特帳款於 111 年底餘額 $4,100K（112 年底已結清為零）。關係人收款天數未顯著拉長，無資金占用跡象。</p><h3 id="三、子公司穿透與資金往來" tabindex="-1">三、子公司穿透與資金往來 <a class="header-anchor" href="#三、子公司穿透與資金往來" aria-label="Permalink to &quot;三、子公司穿透與資金往來&quot;">​</a></h3><p>凌航年報明確揭露「無轉投資事業及子公司」，亦無資金貸與他人、未為他人背書保證。僅向關係人「取得」背書保證以供銀行借款，曾珍／吳惠玲提供保證餘額合計約 $1.01M，實際動支短期借款及票券約 $850K。此為一般銀行授信之正常安排，非利益輸送管道。</p><h3 id="四、2024-年度關係人交易公告檢索" tabindex="-1">四、2024 年度關係人交易公告檢索 <a class="header-anchor" href="#四、2024-年度關係人交易公告檢索" aria-label="Permalink to &quot;四、2024 年度關係人交易公告檢索&quot;">​</a></h3><p>經 MOPS 公開資訊觀測站檢索，凌航於 2024 年度<strong>未公告任何關係人交易事項</strong>。其 2024/1/19 董事會決議取得不動產案，已明確公告「本次交易為關係人交易：否」。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：零子公司異常 — 潛在掏空盲區</strong> — 凌航營收 $30.7B 卻無子公司。此結構可能掩蓋代持安排，使關係人交易脫離審計。若存在地下子公司，凌航可將利潤<strong>溢價轉移</strong>至關聯企業，再以<strong>折價出脫</strong>資產完成利益輸送。此治理空白即財務造假的<strong>泡沫掩蔽所</strong>。建議追蹤 MOPS 轉投資公告，對異常大額固定資產買賣進行壓力測試。</li><li><strong>空頭風險二：人事重疊 — 利益輸送管道未封閉</strong> — 泰特負責人為凌航董事代表，「市場議價」形同虛設。若泰特獲利惡化而凌航仍<strong>溢價銷貨</strong>予泰特，即構成將利潤<strong>出脫</strong>至關聯方的管道。若泰特以<strong>溢價進貨</strong>後再折價銷售，差額即隱性利潤轉移。比對泰特與凌航毛利率，若泰特偏低而凌航偏高，即確認<strong>斷崖式</strong>利潤抽離。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK — finance alias，2023/12 營收 $2,433,940K、營業成本 $2,262,237K；2024/12 營收 $3,073,835K</li><li><strong>年報 PDF</strong>: OK — <code>/Users/kaipro/.openclaw/workspace/work/年報資料庫/3135/2023_Q4_3135_合併.pdf</code>，關係人交易附註（約 P.134-138），含進銷貨明細、應收／應付餘額、背書保證、子公司揭露</li><li><strong>MOPS 公告檢索</strong>: OK — 2024 年度無關係人交易公告，不動產取得案明確標示非關係人交易</li><li><strong>關鍵核對碼</strong>：泰特銷貨 $55,173K + 加工 $355K = $55,528K / 營收 $2,433,940K = 2.28%</li></ul>',21)])])}const u=t(o,[["render",i]]);export{g as __pageData,u as default};
